func TestGettersTag(t *testing.T) {
	t.Run("GetKey", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &Tag{}
		var expected string
		obj.Key = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetKey(), "getter should return the property value")
	})

	t.Run("GetKey_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *Tag
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetKey() // Should return zero value
	})

	t.Run("GetValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &Tag{}
		var expected string
		obj.Value = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetValue(), "getter should return the property value")
	})

	t.Run("GetValue_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *Tag
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetValue() // Should return zero value
	})

	t.Run("GetIsTimestamp", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &Tag{}
		var expected *bool
		obj.IsTimestamp = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetIsTimestamp(), "getter should return the property value")
	})

	t.Run("GetIsTimestamp_NilValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &Tag{}
		obj.IsTimestamp = nil

		// Act & Assert
		assert.Nil(t, obj.GetIsTimestamp(), "getter should return nil when property is nil")
	})

	t.Run("GetIsTimestamp_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *Tag
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetIsTimestamp() // Should return zero value
	})

}

