func TestEnumAcquisitionChannel(t *testing.T) {
	t.Run("NewFromString_ORGANIC", func(t *testing.T) {
		t.Parallel()
		val, err := NewAcquisitionChannelFromString("ORGANIC")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AcquisitionChannel("ORGANIC"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_PAID", func(t *testing.T) {
		t.Parallel()
		val, err := NewAcquisitionChannelFromString("PAID")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AcquisitionChannel("PAID"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_REFERRAL", func(t *testing.T) {
		t.Parallel()
		val, err := NewAcquisitionChannelFromString("REFERRAL")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AcquisitionChannel("REFERRAL"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_OFFLINE", func(t *testing.T) {
		t.Parallel()
		val, err := NewAcquisitionChannelFromString("OFFLINE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AcquisitionChannel("OFFLINE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_GATHERING", func(t *testing.T) {
		t.Parallel()
		val, err := NewAcquisitionChannelFromString("GATHERING")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AcquisitionChannel("GATHERING"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_UNKNOWN", func(t *testing.T) {
		t.Parallel()
		val, err := NewAcquisitionChannelFromString("UNKNOWN")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AcquisitionChannel("UNKNOWN"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewAcquisitionChannelFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewAcquisitionChannelFromString("ORGANIC")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

